import React, { useState, useRef, useEffect } from 'react';
import MessageBubble from './MessageBubble';
import './ChatWindow.css';

function ChatWindow() {
  const [messages, setMessages] = useState([
    {
      sender: 'bot',
      text: 'Hello 👋 I am your AI assistant. How can I help you today?',
    },
  ]);

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const handleSend = async () => {
  if (!input.trim()) return;

  const userMsg = { sender: "user", text: input };
  const currentInput = input;

  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
  messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
};

  setInput("");

  // add user message
  setMessages((prev) => [...prev, userMsg]);

  // IMPORTANT: show typing dots
  setIsTyping(true);

  // FORCE UI RENDER (this is the missing piece)
  await new Promise(requestAnimationFrame);
  await new Promise((r) => setTimeout(r, 50));

  try {
    const res = await fetch("http://127.0.0.1:8000/chat", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        message: currentInput,
        history: messages.map((m) => [m.sender, m.text]),
      }),
    });

    const reader = res.body.getReader();
    const decoder = new TextDecoder();

    let botText = "";

    // add visible bot bubble FIRST
    setMessages((prev) => [
      ...prev,
      { sender: "bot", text: " " }, // important (not empty)
    ]);

    while (true) {
      const { value, done } = await reader.read();
      if (done) break;

      const chunk = decoder.decode(value);

      botText += chunk;

      setMessages((prev) => {
        const updated = [...prev];
        updated[updated.length - 1].text = botText;
        return updated;
      });
    }

  } catch (err) {
    setMessages((prev) => [
      ...prev,
      { sender: "bot", text: "Error: backend unreachable." },
    ]);
  }

};

